219→static inline void vec_mat_mul_rvv_original(const MM_TYPE* src1, const MM_TYPE* src2, MM_TYPE* dst, uint32_t row, uint32_t col, uint32_t col2)
220→{
221→    long curRow, curCol, vl;
222→    long col_4 = col >> 2;
223→    long res_col = col & 3;
224→    long row_8 = row >> 3;
225→    long max_row = row_8 << 3;
226→
227→    for (curRow = 0; curRow < max_row; curRow += 8)
228→    {
229→        const MM_TYPE* C1 = dst + col2 * curRow;
230→        const MM_TYPE* C2 = C1 + col2;
231→        const MM_TYPE* C3 = C2 + col2;
232→        const MM_TYPE* C4 = C3 + col2;
233→        const MM_TYPE* C5 = C4 + col2;
234→        const MM_TYPE* C6 = C5 + col2;
235→        const MM_TYPE* C7 = C6 + col2;
236→        const MM_TYPE* C8 = C7 + col2;
237→
238→        long mulLen = col2;
239→        while (mulLen > 0)
240→        {
241→            NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M2);
242→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); //C
243→            NDS_VEC_VAND_VI(NDS_VEC_V2, NDS_VEC_V2, 0); //C
244→            NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0); //C
245→            NDS_VEC_VAND_VI(NDS_VEC_V6, NDS_VEC_V6, 0); //C
246→            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0); //C
247→            NDS_VEC_VAND_VI(NDS_VEC_V10, NDS_VEC_V10, 0); //C
248→            NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0); //C
249→            NDS_VEC_VAND_VI(NDS_VEC_V14, NDS_VEC_V14, 0); //C
250→            const MM_TYPE* A1 = src1 + curRow * col;
251→            const MM_TYPE* A2 = A1 + col;
252→            const MM_TYPE* A3 = A2 + col;
253→            const MM_TYPE* A4 = A3 + col;
254→            const MM_TYPE* A5 = A4 + col;
255→            const MM_TYPE* A6 = A5 + col;
256→            const MM_TYPE* A7 = A6 + col;
257→            const MM_TYPE* A8 = A7 + col;
258→            const MM_TYPE* B0 = src2 + col2 - mulLen;
259→            const MM_TYPE* B1 = B0 + col2;
260→            const MM_TYPE* B2 = B1 + col2;
261→            const MM_TYPE* B3 = B2 + col2;
262→
263→            for (curCol = 0; curCol < col_4; curCol++)
264→            {
265→                DEF_VLOAD_V(NDS_VEC_V16, B0);
266→                DEF_VLOAD_V(NDS_VEC_V18, B1);
267→                DEF_VLOAD_V(NDS_VEC_V20, B2);
268→                DEF_VLOAD_V(NDS_VEC_V22, B3);
269→                MM_TYPE tmpa00 = *A1++;
270→                MM_TYPE tmpa10 = *A2++;
271→                MM_TYPE tmpa20 = *A3++;
272→                MM_TYPE tmpa30 = *A4++;
273→                NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa00, NDS_VEC_V16);
274→                NDS_VEC_VFMACC_VF(NDS_VEC_V2, tmpa10, NDS_VEC_V16);
275→                NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa20, NDS_VEC_V16);
276→                NDS_VEC_VFMACC_VF(NDS_VEC_V6, tmpa30, NDS_VEC_V16);
277→                MM_TYPE tmpa40 = *A5++;
278→                MM_TYPE tmpa50 = *A6++;
279→                MM_TYPE tmpa60 = *A7++;
280→                MM_TYPE tmpa70 = *A8++;
281→                NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa40, NDS_VEC_V16);
282→                NDS_VEC_VFMACC_VF(NDS_VEC_V10, tmpa50, NDS_VEC_V16);
283→                NDS_VEC_VFMACC_VF(NDS_VEC_V12, tmpa60, NDS_VEC_V16);
284→                NDS_VEC_VFMACC_VF(NDS_VEC_V14, tmpa70, NDS_VEC_V16);
285→
286→                MM_TYPE tmpa01 = *A1++;
287→                MM_TYPE tmpa11 = *A2++;
288→                MM_TYPE tmpa21 = *A3++;
289→                MM_TYPE tmpa31 = *A4++;
290→                NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa01, NDS_VEC_V18);
291→                NDS_VEC_VFMACC_VF(NDS_VEC_V2, tmpa11, NDS_VEC_V18);
292→                NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa21, NDS_VEC_V18);
293→                NDS_VEC_VFMACC_VF(NDS_VEC_V6, tmpa31, NDS_VEC_V18);
294→                MM_TYPE tmpa41 = *A5++;
295→                MM_TYPE tmpa51 = *A6++;
296→                MM_TYPE tmpa61 = *A7++;
297→                MM_TYPE tmpa71 = *A8++;
298→                NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa41, NDS_VEC_V18);
299→                NDS_VEC_VFMACC_VF(NDS_VEC_V10, tmpa51, NDS_VEC_V18);
300→                NDS_VEC_VFMACC_VF(NDS_VEC_V12, tmpa61, NDS_VEC_V18);

  1→// MM_TYPE *nn_mat_mul_kernel_tiling(const MM_TYPE * src1,
  2→//                                   const MM_TYPE * src2,
  3→//                                   MM_TYPE_VQ * tmp_out,
  4→//                                   MM_TYPE * out,
  5→//                                   const uint16_t row,
  6→//                                   const uint16_t col,
  7→//                                   const uint16_t col2,
  8→//                                   const MM_TYPE * bias,
  9→//                                   const uint16_t tiling_size)
 10→// {
 11→// #ifdef ENA_VEC_ISA
 12→#ifdef ENA_DYNAMIC_CALC_CACHE_CONFIG
 13→    unsigned int cache_size_byte = 0, tiling_size = 1;
 14→    vec_calc_tiling_size_and_cache_config(&cache_size_byte, &tiling_size);
 15→#else
 16→    //cache is 512KB
 17→    const unsigned int cache_size_byte = 512 << 10;
 18→#endif
 19→    unsigned int tiling_row_B;
 20→    //col > 8: assume max way is 8 to prevent /0
 21→    if(col < tiling_size && col > 8)
 22→    {
 23→        tiling_row_B = higher_power_2(col);
 24→    }
 25→    else
 26→    {
 27→        tiling_row_B = tiling_size;
 28→    }
 29→    /*
 30→    //4096(col2) * 1B(q7) = 4096B
 31→    //4096B / 64B(line) = 64(row offset of B)
 32→    //2048(line per way) / 64 = 32
 33→    //32 * 4(way) = 128(total num of B in cache)
 34→    //256(tiling_size) is 2 times the 128, second half 128 will cause first half 128 be all evicted
 35→    */
 36→    unsigned int min_col2_byte = cache_size_byte / (tiling_row_B >> 1);
 37→
 38→    //packing can handle just full cache
 39→    min_col2_byte = min_col2_byte >> 1;
 40→    int rvv = RVV_TILING;
 41→    unsigned int col2_byte = col2 * sizeof(MM_TYPE);   //byte of row of B
 42→
 43→    //col2 big enough
 44→    if(col2_byte >= min_col2_byte)
 45→    {
 46→        rvv = RVV_PACKING;
 47→    }
 48→
 49→    //small_matrix also use original_rvv
 50→    unsigned int total = ((row * col) + (col * col2) + (row * col2)); //ABC size
 51→    unsigned int max_size = tiling_size * tiling_size * 3; //max small_matrix size
 52→    if(total < max_size)
 53→    {
 54→        rvv = RVV_ORIGINAL;
 55→    }
 56→
 57→#ifdef ENA_PACKING_HVM
 58→    rvv = RVV_PACKING;
 59→#endif
 60→rvv = RVV_TILING;
 61→    if(rvv == RVV_ORIGINAL)
 62→    {
 63→        //original rvv
 64→        vec_mat_mul_rvv_original_vq(src1, src2, tmp_out, row, col, col2);
 65→    }
 66→    else if(rvv == RVV_TILING)
 67→    {
 68→        /* initial output */
 69→        nn_set_zero_s16((q15_t *)tmp_out, (row * col2 * 2));
 70→        //4*4 by 4*vl
 71→        vec_mat_mul_rvv_tiling_vq(src1, src2, tmp_out, row, col, col2, tiling_size);
 72→    }
 73→    else if(rvv == RVV_PACKING)
 74→    {
 75→        /* initial output */
 76→        nn_set_zero_s16((q15_t *)tmp_out, (row * col2 * 2));
 77→        //packing_rvv
 78→        int status = vec_mat_mul_rvv_packing_vq(src1, src2, tmp_out, row, col, col2, tiling_size);
 79→        if(status == -1)
 80→        {
 81→            return out;
 82→        }
 83→    }
 84→
 85→#if defined(ENA_VEC_ELEN64)
 86→    int vl, avl;
 87→    for(int i = 0; i < row; i++)
 88→    {
 89→        avl = col2;
 90→        const MM_TYPE_VQ *pContri = contri_buf;
 91→        const MM_TYPE_VQ *pOut_scale = out_scale;
 92→        const MM_TYPE_VQ *pOut_shift = out_shift;
 93→        while(avl > 0)
 94→        {
 95→            // Add contribution
 96→            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M4);
 97→            DEF_VLOADVQ_V(NDS_VEC_V0, tmp_out);
 98→            DEF_VLOADVQ_V(NDS_VEC_V24, pContri);
 99→            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V24);
100→
101→            // Quantize down
102→            DEF_VLOADVQ_V(NDS_VEC_V16, pOut_scale);
103→            DEF_VLOADVQ_V(NDS_VEC_V24, pOut_shift);
104→            NDS_VEC_VRSUB_VX(NDS_VEC_V24, NDS_VEC_V24, 30);
105→            NDS_VEC_VWMUL_VV(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V16);  //val * (int64_t)multiplier;
106→            NDS_VEC_VNSRA_WV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V24);  //new_val >> (total_shift - 1);
107→            NDS_VEC_VSSRA_VI(NDS_VEC_V0, NDS_VEC_V0, 1);            //(result + 1) >> 1;
108→
109→            // Add offset
110→            NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, out_offset);
111→            // Clamp the result
112→            NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, act_min);
113→            NDS_VEC_VMIN_VX(NDS_VEC_V0, NDS_VEC_V0, act_max);
114→
115→            // Narrowing result
116→            NDS_VEC_VSETVLI(vl, vl, DEF_VTYPEVW_SEW, NDS_VEC_VTYPE_LMUL_M2);
117→            NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
118→            NDS_VEC_VSETVLI(vl, vl, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M1);
